            const touchEndX = e.changedTouches[0].clientX;
            if (touchStartX - touchEndX > 50) updateCarousel(currentIndex + 1);
            if (touchStartX - touchEndX < -50) updateCarousel(currentIndex - 1);
        });
    };

    // Initialize
    propagateUTMs();
    setupSmoothScroll();
    setupCarousel();
});

